import { useState, useEffect, useCallback } from 'react';
import SecureStorage from '../utils/secureStorage';

export const useSecureStorage = (key, initialValue = null) => {
  const [value, setValue] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadValue();
  }, [key]);

  const loadValue = async () => {
    try {
      setLoading(true);
      const storedValue = await SecureStorage.getSecureData(key);
      setValue(storedValue !== null ? storedValue : initialValue);
      setError(null);
    } catch (err) {
      setError(err);
    } finally {
      setLoading(false);
    }
  };

  const saveValue = useCallback(async (newValue) => {
    try {
      await SecureStorage.saveSecureData(key, newValue);
      setValue(newValue);
      setError(null);
      return true;
    } catch (err) {
      setError(err);
      return false;
    }
  }, [key]);

  const removeValue = useCallback(async () => {
    try {
      await SecureStorage.removeSecureData(key);
      setValue(initialValue);
      setError(null);
      return true;
    } catch (err) {
      setError(err);
      return false;
    }
  }, [key, initialValue]);

  return { value, loading, error, saveValue, removeValue, reload: loadValue };
};

