// ExampleUsage.js
import React, { useEffect } from 'react';
import { View, Text, Button, ActivityIndicator } from 'react-native';
import { useUserProfile, useAuthTokens, usePaymentInfo } from './hooks/useSecureStorage';
import SecureStorage from './utils/secureStorage';

const ExampleUsage = () => {
  const { profile, loading: profileLoading, saveProfile, clearProfile } = useUserProfile();
  const { tokens, loading: tokensLoading, saveTokens, clearTokens } = useAuthTokens();
  const { paymentInfo, loading: paymentLoading, savePaymentInfo, clearPaymentInfo } = usePaymentInfo();

  const handleSaveProfile = async () => {
    const userData = {
      id: '12345',
      name: 'John Doe',
      email: 'john@example.com',
      phone: '+1234567890',
    };
    await saveProfile(userData);
  };

  const handleSaveTokens = async () => {
    await saveTokens('auth_token_xyz123', 'refresh_token_abc456');
  };

  const handleSavePayment = async () => {
    const payment = {
      cardNumber: '4111111111111111',
      cardHolder: 'John Doe',
      expiryDate: '12/25',
      cvv: '123',
    };
    await savePaymentInfo(payment);
  };

  const handleClearAll = async () => {
    await SecureStorage.clearAll();
    await clearProfile();
    await clearTokens();
    await clearPaymentInfo();
  };

  if (profileLoading || tokensLoading || paymentLoading) {
    return <ActivityIndicator size="large" />;
  }

  return (
    <View style={{ padding: 20 }}>
      <Text>User Profile: {JSON.stringify(profile)}</Text>
      <Text>Auth Token: {tokens.authToken}</Text>
      <Text>Payment Info: {JSON.stringify(paymentInfo)}</Text>
      
      <Button title="Save Profile" onPress={handleSaveProfile} />
      <Button title="Save Tokens" onPress={handleSaveTokens} />
      <Button title="Save Payment" onPress={handleSavePayment} />
      <Button title="Clear All" onPress={handleClearAll} />
    </View>
  );
};

export default ExampleUsage;